import type { JobTriggerResponse, BlogGeneratePayload } from '@growth-engine/types'
import { sdkFetch } from '../client'

export async function triggerBlogGen(payload: BlogGeneratePayload): Promise<JobTriggerResponse> {
  const res = await sdkFetch<JobTriggerResponse>('/jobs', {
    method: 'POST',
    body: JSON.stringify({ type: 'blog.generate', payload }),
  })
  if (res.error) {
    throw new Error(res.error)
  }
  return res.data
}
