'use client'

import { useState, useEffect } from 'react'
import type { SDKVersionManifest } from '@growth-engine/types'
import { sdkFetch } from '../client'

interface UseSDKStatusResult {
  manifest: SDKVersionManifest | null
  loading: boolean
  error: string | null
}

export function useSDKStatus(): UseSDKStatusResult {
  const [manifest, setManifest] = useState<SDKVersionManifest | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const res = await sdkFetch<SDKVersionManifest>('/sdk-status')
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setManifest(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [])

  return { manifest, loading, error }
}
