'use client'

import { useState, useEffect, useCallback } from 'react'
import type { Job } from '@growth-engine/types'
import { sdkFetch } from '../client'

interface UseJobStatusResult {
  job: Job | null
  loading: boolean
  error: string | null
  refresh: () => void
}

export function useJobStatus(jobId: string | null): UseJobStatusResult {
  const [job, setJob] = useState<Job | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const load = useCallback(async () => {
    if (!jobId) return
    setLoading(true)
    const res = await sdkFetch<Job>(`/jobs/${encodeURIComponent(jobId)}`)
    if (res.error) {
      setError(res.error)
    } else {
      setJob(res.data)
    }
    setLoading(false)
  }, [jobId])

  useEffect(() => {
    void load()
  }, [load])

  return { job, loading, error, refresh: load }
}
