import type { SDKResponse } from '@growth-engine/types'

const BASE_PATH = '/api/rs'

export async function sdkFetch<T>(path: string, options?: RequestInit): Promise<SDKResponse<T>> {
  const url = `${BASE_PATH}${path}`
  const res = await fetch(url, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...options?.headers,
    },
  })

  if (!res.ok) {
    return {
      data: null as unknown as T,
      error: `Request failed with status ${res.status}`,
      status: res.status,
    }
  }

  const data = (await res.json()) as T
  return { data, error: null, status: res.status }
}
