'use client'

import { useState, useEffect } from 'react'
import type { Form } from '@growth-engine/types'
import { sdkFetch } from '../client'

interface UseFormsResult {
  forms: Form[]
  loading: boolean
  error: string | null
}

interface UseFormResult {
  form: Form | null
  loading: boolean
  error: string | null
}

export function useForms(): UseFormsResult {
  const [forms, setForms] = useState<Form[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const res = await sdkFetch<Form[]>('/forms?action=list')
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setForms(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [])

  return { forms, loading, error }
}

export function useForm(slug: string): UseFormResult {
  const [form, setForm] = useState<Form | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const res = await sdkFetch<Form | null>(
        `/forms?action=get&slug=${encodeURIComponent(slug)}`,
      )
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setForm(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [slug])

  return { form, loading, error }
}

export async function submitForm(
  slug: string,
  data: Record<string, unknown>,
): Promise<{ ok: boolean, id?: string, error?: string }> {
  const res = await sdkFetch<{ ok: boolean, id?: string, error?: string }>(
    `/forms?action=submit&slug=${encodeURIComponent(slug)}`,
    {
      method: 'POST',
      body: JSON.stringify({ data }),
    },
  )
  if (res.error) {
    return { ok: false, error: res.error }
  }
  return res.data
}
