'use client'

import { createContext, useContext, useEffect } from 'react'
import type { ReactNode } from 'react'
import type { SDKVersionManifest } from '@growth-engine/types'
import { sdkFetch } from './client'
import { SDK_VERSION } from './version'

interface GrowthEngineContextValue {
	locale?: string | undefined
	tenantSlug?: string | undefined
}

const GrowthEngineContext = createContext<GrowthEngineContextValue>({})

function matchesPattern(version: string, pattern: string): boolean {
	const regex = new RegExp('^' + pattern.replace(/\./g, '\\.').replace(/x/g, '\\d+') + '$')
	return regex.test(version)
}

export function GrowthEngineProvider({
	children,
	locale,
	tenantSlug,
}: {
	children: ReactNode
	locale?: string | undefined
	tenantSlug?: string | undefined
}) {
	useEffect(() => {
		let cancelled = false

		async function checkVersion() {
			const res = await sdkFetch<SDKVersionManifest>('/sdk-status')
			if (cancelled || res.error) return
			const manifest = res.data

			const isDeprecated = manifest.deprecated.some((p) => matchesPattern(SDK_VERSION, p))
			const isUnsupported = manifest.unsupported.some((p) => matchesPattern(SDK_VERSION, p))

			if (isUnsupported) {
				console.error(
					`[GrowthEngine] SDK version ${SDK_VERSION} is unsupported. Please upgrade to ${manifest.latest}.`,
				)
			} else if (isDeprecated) {
				console.warn(
					`[GrowthEngine] SDK version ${SDK_VERSION} is deprecated. Please upgrade to ${manifest.latest}.`,
				)
			}
		}

		void checkVersion()
		return () => {
			cancelled = true
		}
	}, [])

	return (
		<GrowthEngineContext.Provider value={{ locale, tenantSlug }}>
			{children}
		</GrowthEngineContext.Provider>
	)
}

export function useGrowthEngine() {
	return useContext(GrowthEngineContext)
}
