'use client'

import { useState, useEffect } from 'react'
import type { BlogPost, SocialPost } from '@growth-engine/types'
import { sdkFetch } from '../client'

type ContentType = 'blog' | 'social'

interface UseContentResult<T> {
  posts: T[]
  loading: boolean
  error: string | null
}

export function useContent(type: 'blog'): UseContentResult<BlogPost>
export function useContent(type: 'social'): UseContentResult<SocialPost>
export function useContent(type: ContentType): UseContentResult<BlogPost | SocialPost> {
  const [posts, setPosts] = useState<(BlogPost | SocialPost)[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const res = await sdkFetch<(BlogPost | SocialPost)[]>(`/content?type=${type}`)
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setPosts(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [type])

  return { posts, loading, error }
}

export async function fetchBlog(slug: string): Promise<BlogPost | null> {
  const res = await sdkFetch<BlogPost>(`/content?type=blog&slug=${encodeURIComponent(slug)}`)
  return res.error ? null : res.data
}

export async function getSocialPosts(
  platform: 'instagram' | 'linkedin' | 'facebook',
): Promise<SocialPost[]> {
  const res = await sdkFetch<SocialPost[]>(
    `/content?type=social&platform=${encodeURIComponent(platform)}`,
  )
  return res.error ? [] : res.data
}
